(422, 5028, 19, 0, '24', 'Khush', 'Student', NULL, 'Germany ', 'Shruti', 'null', '', '', '', '1', '1', '1', NULL, '1', 0, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'no_book', NULL, 'Khushdeep kumar', '9872612342', 'No', 'Addiction to PMO', 'no', 'no', '', 'There are lots of thinks i am going through but major most hit was when broke up with my gf on 20 march very next day i get panic attacks and restlessness, anxiety, depression. More it was like a drugs taken away from drug addict. ', 'agree', 'agree', NULL, '2024-11-25', '1. Follow up - Present status and follow up on the tips suggested earlier\r\n2. Mindfulness based relaxation \r\n', 'no_book', 0, 0, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-04-06 11:38:57', '2024-04-06 11:38:57'),
(429, 5028, 19, 0, '24', 'Khush', 'Student', NULL, 'Germany ', 'Shruti', 'null', '', '', '', '1', '2', '2', NULL, '1', 0, '2024-04-15', '10:45am-11:30am', 'https://meet.google.com/way-jxia-drb?authuser=0', 'Just amazing. Learned new things about myself of which i was unaware. Mam is so helpful and experienced in her work', 'No request', 'Yes', '4', '4', '4', '4', 'completed', NULL, 'Khushdeep kumar', '9872612342', 'No', 'Imagination world get attached to person ', 'no', 'no', '', 'Build imaginary world around a person and get attached to that person always in fear of losing that world and person', 'agree', 'agree', 'Client reported improvement in mental health, reduced negative thoughts increases mindfulness & acceptance of reality, increased self acceptance. He was observed to be motivated, working on his mental health & personal growth. \r\n\r\nWorked on: \r\n•Control & anxiety correlation \r\n•Decreasing co- dependence by increasing self dependence & esteem\r\n•Psycheducated about cognitive flexibility & cons of over- planning (stemming from high anxiety)\r\n•Addressed the unhealthy comparison of the present with imagination, maximization & minimisation\r\n•Locus of control\r\n\r\nApproach used: CBT', '2024-11-25', '1. Follow up - Present status and follow up on the tips suggested earlier\r\n2. Mindfulness based relaxation \r\n', 'no_book', 1, 1, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-04-10 06:36:50', '2024-04-10 06:39:20'),
