(434, 5028, 19, 0, '24', 'Khush', 'Student', NULL, 'Germany ', 'Shruti', 'null', '', '', '', '4', '3', '3', NULL, '3', 0, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'no_book', NULL, 'Khushdeep kumar', '9872612342', 'No', 'Over control', 'no', 'no', '', 'In last session i get to know that i was over controlling things. I was doing things in the right way but along with that expecting particular result and when I didn’t get i get irritated and anxious but when i get results i never appreciated ', 'agree', 'agree', NULL, '2024-11-25', '1. Follow up - Present status and follow up on the tips suggested earlier\r\n2. Mindfulness based relaxation \r\n', 'no_book', 0, 0, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-04-15 10:59:25', '2024-04-15 10:59:25'),
