(436, 4976, 19, 0, '22', 'He', 'Student ', NULL, 'NA', 'Garima Sharma', 'null', '', '', '', '4', '3', '3', NULL, '3', 0, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'no_book', NULL, 'Na', 'Na', 'I feel like I don\\\'t have any entity in this world and also don\\\'t possess any identity. I get attached quickly which distract me from my aim', 'Emotional attachment, introvert nature', 'no', 'no', '', '', 'agree', 'agree', NULL, NULL, NULL, 'no_book', 0, 0, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-04-16 03:47:58', '2024-04-16 03:47:58'),
(440, 5028, 19, 0, '24', 'Khush', 'Student', NULL, 'Shruti', 'Shruti', 'null', '', '', '', '3', '2', '2', NULL, '2', 0, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'no_book', NULL, 'Khushdeep kumar', '9872612342', 'No', 'Addicted to a person', 'no', 'no', '', 'Overworked on relationship and get addicted to it', 'agree', 'agree', NULL, '2024-11-25', '1. Follow up - Present status and follow up on the tips suggested earlier\r\n2. Mindfulness based relaxation \r\n', 'psy_shortnote', 0, 0, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-04-16 14:22:49', '2024-04-16 14:22:49'),
(446, 5028, 19, 0, '24', 'Khush', 'Student', NULL, 'Germany ', 'Shruti', 'null', '', '', '', '4', '3', '4', NULL, '3', 0, '2024-04-22', '10:45am-11:30am', 'https://meet.google.com/iry-xcju-uep?authuser=0', 'Amazing ', 'No request ', 'Yes', '4', '4', '4', '4', 'completed', NULL, 'Khushdeep kumar', '9872612342', 'No', 'Chronically attached to a person emotionally & S*x', 'no', 'no', '', 'Overworked on relationships due to addictions and attachment ', 'agree', 'agree', 'Client reported further improvement in mental health. He mentioned \"being happy like never before\". Client was experiencing anxiety that was not self provoken or proken through thoughts (mostly subconscious)\r\n\r\nWorked on:\r\n* Psycheducated about: conscious & subconscious processes\r\n* Discussed some childhood trauma adaptations\r\n* Imaginary thoughts triggered automatically which led to negative self talk and further experiencing negative emotions\r\n* Increased Relaxation interventions\r\n* Self affirmations in attempt to alter belief systems at the subconscious level at designated time \r\n* Discussed the list of the difference between his conscious & subconscious anxiety\r\n\r\nApproach used: CBT', '2024-11-25', '1. Follow up - Present status and follow up on the tips suggested earlier\r\n2. Mindfulness based relaxation \r\n', 'psy_shortnote', 1, 1, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-04-17 14:54:22', '2024-04-17 14:55:24'),
(457, 5886, 19, 0, '24', 'she/her', 'Sales executive', NULL, 'PensionBox', 'no', 'null', '', '', '', '2', '2', '1', NULL, '1', 0, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'no_book', NULL, 'Arshita', '8360965322', 'no', 'Depression', 'ocassional', 'yes', '', 'I am not feeling well, i dont know what else to say, I just cant handle crying anymore', 'agree', 'agree', NULL, NULL, NULL, 'psy_shortnote', 0, 0, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-04-23 08:26:33', '2024-04-23 08:26:33'),
(459, 5028, 19, 0, '24', 'Khush', 'Self employed ', NULL, 'Germany ', 'Shruti', 'null', '', '', '', '4', '4', '4', NULL, '4', 0, '2024-05-01', '10:45am-11:30am', 'https://meet.google.com/ieq-peaq-dnu?authuser=0', 'Amazing ', 'No', 'Yes', '4', '4', '4', '4', 'completed', NULL, 'Khushdeep kumar', '9872612342', 'No', 'Subconscious mind', 'no', 'no', '', 'Thoughts of ex girlfriend got stuck in subconscious mind that kept on triggering at random moments ', 'agree', 'agree', 'Client reported subconscious inner dialogue pulling towards instant gratification (working on id). High levels of cognitive dissonance was observed, Anxiety created due to cognitive dissonance (mostly subconscious). Client reported he was \"constantly trying to fight these voices\".He also reported sadness occurring as a result of negative comparison\r\n\r\nWork done:\r\nCognitive restructuring to manage cognitive dissonance\r\nHabituation\r\nPsychoeducation on consequences of fighting the subconscious voices\r\nIdentifying the underlying needs of the subconscious due to which it is creating anxiety + alternate ways to meet those needs. Need of emotional safety & comfort was identified & worked on\r\nEmbracing instead of fighting the inner voices\r\nWorked on self esttem\r\neducated about types of comparison, consequences of negative comparison', '2024-11-25', '1. Follow up - Present status and follow up on the tips suggested earlier\r\n2. Mindfulness based relaxation \r\n', 'psy_shortnote', 1, 1, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-04-24 20:05:23', '2024-04-24 20:06:56'),
