(478, 6251, 19, 0, '35', 'He/Him', 'Senior manager', NULL, 'Simpl', 'Na', 'null', '', '', '', '1', '1', '2', NULL, '1', 0, '', '', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'no_book', NULL, 'Mayuri', '8197442931', 'Nil', 'Extreme fatigue, low motivation, procrastination ', 'ocassional', 'no', '', 'I am feeling very low all the time, with no motivation to do anything and procrastinate everything', 'agree', 'agree', NULL, NULL, NULL, 'psy_shortnote', 0, 0, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-05-01 05:28:23', '2024-05-01 05:28:23'),
(479, 5028, 19, 0, '24', 'Khush', 'Student', NULL, 'Germany ', 'Shruti', 'null', '', '', '', '4', '4', '4', NULL, '4', 0, '2024-05-06', '10:45am-11:30am', 'https://meet.google.com/fcp-qgyr-uiv?authuser=0', 'Amazing ', 'No', 'Yes', '5', '5', '5', '5', 'completed', NULL, 'Khushdeep kumar', '9872612342', 'No', 'Life totally controlled by subconscious mind ', 'no', 'no', '', 'Already shared', 'agree', 'agree', 'Client reported a lot of improvement including experiencing happiness, ability to enjoy moments of life, enhanced patience, ability to identify triggers, becoming less triggered, consistency with routine, forming discipline and focussing on mental health. \r\nHe is able to observe his triggers, and work with them effectively enough to not be affected by them, Client mentioned reduction in symptoms of Anxiety and Depression.\r\n\r\nWorked on:\r\n1) Accepting Subconscious mind instead of fighting it. Consequences of over-controlling the mind\r\n2) All or none cognitive distortion\r\n3) Survival brain characteristics and providing safety\r\n4) Creating a safe space for himself\r\n5) Observing the underlying fears leading to negative thoughts, emotions & actions', '2024-11-25', '1. Follow up - Present status and follow up on the tips suggested earlier\r\n2. Mindfulness based relaxation \r\n', 'psy_shortnote', 1, 1, NULL, NULL, 0, NULL, 0, NULL, NULL, NULL, 0, '2024-05-02 07:55:03', '2024-05-02 07:55:44'),
