tion\"},{\"option\":\"Better motivation\"},{\"option\":\"Improved self-worth\"},{\"option\":\"All of the above\"}]},\"10\":{\"question\":\"How hopeful are you about your journey of recovery?\",\"options\":[{\"option\":\"Very hopeful\"}]}}', NULL, 0, '2025-04-14 17:07:50', '2025-04-17 03:34:13'),
