(931, 10866, 44, 0, '', NULL, NULL, NULL, NULL, NULL, 'null', NULL, NULL, 'null', '4', '4', '4', NULL, '4', 0, '2025-07-17', '2:00pm-2:45pm', 'https://meet.google.com/uro-eufe-crx', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'completed', NULL, NULL, NULL, NULL, '', 'null', 'null', NULL, NULL, 'agree', 'agree', NULL, NULL, NULL, 'psy_shortnote', 0, 1, NULL, NULL, 0, NULL, 0, 11, '{\"1\":{\"question\":\"How often do you and your partner communicate openly?\",\"options\":[{\"option\":\"Sometimes\"}]},\"2\":{\"question\":\"What would you like to improve most in your relationship?\",\"options\":[{\"option\":\"Communication\"},{\"option\":\"Trust\"},{\"option\":\"Quality time\"},{\"option\":\"Conflict resolution\"}]},\"3\":{\"question\":\"How comfortable are you expressing your emotions to your partner?\",\"options\":[{\"option\":\"Somewhat comfortable\"}]},\"4\":{\"question\":\"How often do you feel that disagreements turn into arguments?\",\"options\":[{\"option\":\"Occasionally\"}]},\"5\":{\"question\":\"Do you feel supported by your partner?\",\"options\":[{\"option\":\"Sometimes\"}]},\"6\":{\"question\":\"What is your biggest challenge as a couple?\",\"options\":[{\"option\":\"Communication issues\"},{\"option\":\"Different goals\"},{\"option\":\"Emotional connection\"}]},\"7\":{\"question\":\"How often do you feel your needs are understood in the relationship?\",\"options\":[{\"option\":\"Sometimes\"}]},\"8\":{\"question\":\"How would you rate the level of trust between you and your partner?\",\"options\":[{\"option\":\"High\"}]},\"9\":{\"question\":\"How often do you spend quality time together?\",\"options\":[{\"option\":\"Weekly\"}]},\"10\":{\"question\":\"Are you both committed to work on the relationship?\",\"options\":[{\"option\":\"Somewhat supported\"}]}}', NULL, 0, '2025-07-16 18:48:47', '2025-07-16 18:48:47'),
